    public static IActionResult Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger logger)
    {
        try
        {
            string databaseServer = Environment.GetEnvironmentVariable("DatabaseServer");
            string databaseUsername = Environment.GetEnvironmentVariable("DatabaseUsername");
            string databasePassword = Environment.GetEnvironmentVariable("DatabasePassword");
            string databaseName = Environment.GetEnvironmentVariable("DatabaseName");

            string connectionString = $"Server=tcp:{databaseServer},1433;Initial Catalog={databaseName};User ID={databaseUsername};Password={databasePassword};Encrypt=True;TrustServerCertificate=False;Connection Timeout=30;";
            SqlConnection connection = new SqlConnection(connectionString);

            connection.Open();

            string filterClause = "";
            string orderClause = "";

            string nameFilter = req.Query["name"];
            if (!string.IsNullOrEmpty(nameFilter))
            {
                filterClause += " AND Name LIKE '%{0}%'";
